import{mostrarResultado}from"../../renderResult.js";export function render(t){const{vista:o,productos:n,detalle:r,carrito:d,total:a}=t.respuesta,i=0===d.length?"<p>El carrito está vacío.</p>":`<table border="1">\n            <thead><tr><th>Producto</th><th>Precio</th><th>Uds.</th><th>Subtotal</th><th></th></tr></thead>\n            <tbody>\n                ${d.map(t=>`\n                    <tr>\n                        <td>${t.nombre}</td><td>${t.precio} €</td>\n                        <td>${t.cantidad}</td><td>${t.subtotal} €</td>\n                        <td><button onclick="sendPrompt('accion=eliminar&productoId=${t.id}')">🗑</button></td>\n                    </tr>`).join("")}\n            </tbody>\n            <tfoot><tr><td colspan="3"><b>Total</b></td><td colspan="2"><b>${a} €</b></td></tr></tfoot>\n        </table>`;if("detalle"===o)mostrarResultado(`\n            <button onclick="sendPrompt('accion=listar')">← Volver</button>\n            <h3>${r.nombre}</h3>\n            <img src="${r.imagen}" alt="${r.nombre}" style="max-width:200px;"><br>\n            <p>${r.descripcion}</p>\n            <b>Precio: ${r.precio} €</b><br>\n            <button onclick="sendPrompt('accion=añadir&productoId=${r.id}')">🛒 Añadir al carrito</button>\n            <hr><h3>Carrito</h3>${i}\n        `);else{const t=n.map(t=>`\n            <div style="border:1px solid #ccc; padding:10px; margin:5px; display:inline-block; width:150px;">\n                <img src="${t.imagen}" alt="${t.nombre}" style="width:100%;"><br>\n                <b>${t.nombre}</b><br>${t.precio} €<br>\n                <button onclick="sendPrompt('accion=detalle&productoId=${t.id}')">🔍 Detalle</button>\n                <button onclick="sendPrompt('accion=añadir&productoId=${t.id}')">🛒 Comprar</button>\n            </div>`).join("");mostrarResultado(`\n            <h3>Catálogo</h3>${t}\n            <hr><h3>Carrito</h3>${i}\n        `)}}//# sourceMappingURL=ejercicio3.js.map
